use std::{convert::Infallible,path::{Path,PathBuf}};use kameo::{Actor,actor::{ActorRef,Spawn},message::{Context,Message}};use name_table::NameTable;use signal_logos::{Reply,Request,Rejection};use signal_sema_storage::{DocumentKind,DocumentPayload,Reply as SReply,Request as SRequest};use textual_rust::RustSource;use tokio::{io::{AsyncReadExt,AsyncWriteExt},net::UnixStream};
#[derive(Debug,thiserror::Error)]pub enum Error{#[error("io: {0}")]Io(#[from]std::io::Error),#[error("projection: {0}")]Projection(String),#[error("actor: {0}")]Actor(String)}type Result<T>=std::result::Result<T,Error>;
async fn exchange(p:&Path,q:&SRequest)->Result<SReply>{let mut s=UnixStream::connect(p).await?;let b=signal_sema_storage::Wire::encode_request(q).map_err(|e|Error::Projection(e.to_string()))?;s.write_u32_le(b.len()as u32).await?;s.write_all(&b).await?;let n=s.read_u32_le().await?as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;rkyv::from_bytes::<SReply,rkyv::rancor::Error>(&b).map_err(|e|Error::Projection(e.to_string()))}
pub struct SemaPlane{socket:PathBuf,reads:u64}impl Actor for SemaPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}pub struct Fetch(pub SRequest);impl Message<Fetch> for SemaPlane{type Reply=Result<SReply>;async fn handle(&mut self,m:Fetch,_:&mut Context<Self,Self::Reply>)->Self::Reply{self.reads+=1;exchange(&self.socket,&m.0).await}}
pub struct NexusPlane{sema:ActorRef<SemaPlane>,projected:u64}impl Actor for NexusPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}pub struct Dispatch(pub Request);impl Message<Dispatch> for NexusPlane{type Reply=Result<Reply>;async fn handle(&mut self,m:Dispatch,_:&mut Context<Self,Self::Reply>)->Self::Reply{match m.0{Request::ProjectRust{scope:_,logos}=>{self.projected+=1;let fetched=self.sema.ask(Fetch(SRequest::HashFetch{hash:logos})).send().await.map_err(|e|Error::Actor(e.to_string()))?;let SReply::Document(Some(document))=fetched else{return Ok(Reply::Rejected(Rejection::LogosNotFound))};let summary=signal_sema_storage::SlotSummary{key:document.key.clone(),version:document.version,hash:document.hash};let DocumentPayload::Logos{items,names}=document.payload else{return Ok(Reply::Rejected(Rejection::WrongDocumentKind))};let names=NameTable::from_archive_bytes(&names.0).map_err(|e|Error::Projection(e.to_string()))?;let mut rust=String::new();for item in items{let bytes=rkyv::to_bytes::<rkyv::rancor::Error>(&item).map_err(|e|Error::Projection(e.to_string()))?;let item=rkyv::from_bytes::<projection_core_logos::CoreItem,rkyv::rancor::Error>(&bytes).map_err(|e|Error::Projection(e.to_string()))?;rust.push_str(RustSource::project_item(&item,&names).map_err(|e|Error::Projection(e.to_string()))?.as_str());rust.push('\n');}Ok(Reply::RustProjected{rust,source:summary})},Request::List{scope}=>{let r=self.sema.ask(Fetch(SRequest::List{scope,kind:Some(DocumentKind::Logos)})).send().await.map_err(|e|Error::Actor(e.to_string()))?;Ok(match r{SReply::Listed(v)=>Reply::Listed(v),_=>Reply::Rejected(Rejection::StorageFailed)})},Request::Subscribe{scope}=>{let r=self.sema.ask(Fetch(SRequest::Subscribe{scope,kind:Some(DocumentKind::Logos)})).send().await.map_err(|e|Error::Actor(e.to_string()))?;Ok(match r{SReply::Subscribed{..}=>Reply::Subscribed,_=>Reply::Rejected(Rejection::StorageFailed)})}}}}
pub struct SignalPlane{nexus:ActorRef<NexusPlane>,admitted:u64}impl Actor for SignalPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}impl Message<Dispatch> for SignalPlane{type Reply=Result<Reply>;async fn handle(&mut self,m:Dispatch,_:&mut Context<Self,Self::Reply>)->Self::Reply{self.admitted+=1;self.nexus.ask(m).send().await.map_err(|e|Error::Actor(e.to_string()))}}
#[derive(Clone)]pub struct Runtime{signal:ActorRef<SignalPlane>}impl Runtime{pub fn new(socket:PathBuf)->Self{let sema=SemaPlane::spawn(SemaPlane{socket,reads:0});let nexus=NexusPlane::spawn(NexusPlane{sema,projected:0});Self{signal:SignalPlane::spawn(SignalPlane{nexus,admitted:0})}}pub async fn request(&self,q:Request)->Result<Reply>{self.signal.ask(Dispatch(q)).send().await.map_err(|e|Error::Actor(e.to_string()))}}
